import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Billing Engine","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Billing Engine | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/billing-engine"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Billing Engine | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/billing-engine"}]]},"headers":[],"relativePath":"developer-guide/billing-engine.md","filePath":"developer-guide/billing-engine.md","lastUpdated":1784743690000}'),i={name:"developer-guide/billing-engine.md"};function s(d,e,r,c,l,p){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="billing-engine" tabindex="-1">Billing Engine <a class="header-anchor" href="#billing-engine" aria-label="Permalink to &quot;Billing Engine&quot;">​</a></h1><p>Gateway-agnostic billing orchestration. Business licensing remains <code>workspace_module_subscriptions</code>; the engine handles purchase settlement, consolidated invoicing, and payment ledger writes.</p><p>See also: <a href="/developer-guide/payment-gateways-overview">Payment Gateway Architecture</a>.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Piece</th><th>Role</th></tr></thead><tbody><tr><td><code>BillingEngine</code></td><td>Orchestrates install → invoice → payment → activation</td></tr><tr><td><code>GatewayManager</code></td><td>Resolves <code>PaymentGatewayInterface</code> drivers (<code>manual</code>, <code>stripe</code>)</td></tr><tr><td><code>ManualGateway</code></td><td>Synchronous settle (admin/manual payments)</td></tr><tr><td><code>StripeGateway</code></td><td>Checkout + webhook normalization to <code>GatewayEvent</code> (<strong>only</strong> Cashier/Stripe touchpoint)</td></tr><tr><td><code>ProrationCalculator</code></td><td>Mid-cycle purchase amount from workspace <code>proration_mode</code></td></tr><tr><td><code>InvoiceService</code> / <code>PaymentService</code></td><td>Ledger CRUD</td></tr><tr><td><code>PaymentGatewayService</code></td><td>Admin gateway management</td></tr><tr><td><code>GatewayModulePriceService</code></td><td>Per-gateway module product/price mappings (<code>payment_gateway_module_prices</code>)</td></tr></tbody></table><p>Drivers implement <code>PaymentGatewayInterface</code>. Cashier tables are a Stripe mirror only — not the licensing or invoice SoT. <code>BillingEngine</code> must never import Stripe or Cashier. Modules never store provider price IDs.</p><h2 id="proration-modes" tabindex="-1">Proration modes <a class="header-anchor" href="#proration-modes" aria-label="Permalink to &quot;Proration modes&quot;">​</a></h2><p>Set per workspace (<code>tenants.proration_mode</code>) or default via system setting.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Mid-cycle purchase charge</th></tr></thead><tbody><tr><td><code>prorated</code></td><td>Remaining days in current period ÷ period length × module price</td></tr><tr><td><code>free_until_next</code></td><td><code>0</code> until next consolidated invoice</td></tr><tr><td><code>none</code></td><td>Full period price immediately</td></tr></tbody></table><h2 id="purchase-sequence-purchasemodule" tabindex="-1">Purchase sequence (<code>purchaseModule</code>) <a class="header-anchor" href="#purchase-sequence-purchasemodule" aria-label="Permalink to &quot;Purchase sequence (\`purchaseModule\`)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /tenants/{tenant}/modules  →  ModuleSubscriptionService::install</span></span>
<span class="line"><span>  ├─ non-billable / included → status=active immediately</span></span>
<span class="line"><span>  └─ billable → status=pending</span></span>
<span class="line"><span>       ├─ persist payment_gateway_id on the subscription</span></span>
<span class="line"><span>       ├─ manual gateway → draft invoice (proration line) → open → mark payment succeeded → activate</span></span>
<span class="line"><span>       └─ other gateway → assert gateway price mapping when required → createCheckout (refs on CheckoutRequest) → redirect; webhook activates on success</span></span></code></pre></div><h2 id="consolidated-billing-sequence" tabindex="-1">Consolidated billing sequence <a class="header-anchor" href="#consolidated-billing-sequence" aria-label="Permalink to &quot;Consolidated billing sequence&quot;">​</a></h2><p>Command: <code>php artisan billing:run-consolidated</code> (scheduled daily in <code>routes/console.php</code>).</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>For each tenant where next_billing_at &lt;= now:</span></span>
<span class="line"><span>  1. Collect active, billable workspace_module_subscriptions that are platform-managed</span></span>
<span class="line"><span>     (no payment gateway, or gateway does not supportRecurring())</span></span>
<span class="line"><span>  2. Skip invoice creation if none (recurring-gateway renewals stay with the provider)</span></span>
<span class="line"><span>  3. Create draft invoice with one line per subscription (type=module)</span></span>
<span class="line"><span>  4. Open invoice</span></span>
<span class="line"><span>  5. Record payment; auto-succeed on manual gateway only</span></span>
<span class="line"><span>  6. Advance next_billing_at by one month (anchor day 1–28)</span></span></code></pre></div><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><ul><li><code>POST /webhooks/gateways/{code}</code> → driver <code>parseWebhook</code> → <code>BillingEngine::handleGatewayEvent</code></li><li><code>POST /stripe/webhook</code> → Cashier handlers + same Billing Engine dispatch</li></ul><p>Tenant resolution (provider-agnostic; no Stripe/Cashier columns in the engine):</p><ol><li><code>GatewayEvent.tenantId</code> (set by the driver when the customer map resolves)</li><li><code>providerSubscriptionId</code> → <code>workspace_module_subscriptions</code></li><li><code>meta.payment_id</code> → <code>payments</code> (covers <code>payment_failed</code> when no customer → tenant map exists)</li></ol><h2 id="default-gateway" tabindex="-1">Default gateway <a class="header-anchor" href="#default-gateway" aria-label="Permalink to &quot;Default gateway&quot;">​</a></h2><p><code>default_payment_gateway</code> system setting → <code>payment_gateways.is_default</code> → <code>manual</code> (see <code>config/core-platform.php</code>).</p>`,20)])])}const m=a(i,[["render",s]]);export{u as __pageData,m as default};
